#include <stdio.h>

int main() {
    for (int i = 1; i <= 100; i++) {
        if (i == 4) {
            printf("Emergency Stop!\n");
            break; // Exits the loop completely
        }
        printf("Loop %d\n", i);
    }

    printf("Done!");
    return 0;
}

#include <stdio.h>

int main() {
    for (int i = 1; i <= 5; i++) {
        if (i % 2 == 0) {
            continue; // Skip the rest of this cycle!
        }
        printf("Odd Number: %d\n", i);
    }

    return 0;
}
